// The bot reacts ONLY when it is @mentioned (context.mentions contains the bot
// number) and the message is not its own. The command is the first non-@ word.
const cfg = $('Config').first().json;
const BOT = String(cfg.botNumber || '').replace(/[^0-9]/g, '');
const body = $('WhatsApp Inbound').first().json.body || {};
const msg = (body.messages && body.messages[0]) || {};
const text = (msg.text && msg.text.body) ? String(msg.text.body).trim() : '';
const from = String(msg.from || '').replace(/[^0-9]/g, '');
const chatId = msg.chat_id || '';
const fromMe = msg.from_me === true;
const mentions = (msg.context && Array.isArray(msg.context.mentions)) ? msg.context.mentions.map(m => String(m).replace(/[^0-9]/g, '')) : [];
const isBot = fromMe || (BOT.length > 0 && from === BOT);
const mentioned = !isBot && BOT.length > 0 && mentions.includes(BOT);
const words = text.split(' ').filter(t => t && t.charAt(0) !== '@');
const command = mentioned ? (words[0] || '').toLowerCase() : '';
const targetPlayers = mentions.filter(m => m && m !== BOT);
return [{ json: { mentioned, command, number: from, chatId, text, targetPlayers } }];

// ── AI intent classification (Claude Haiku). The AI classifies intent ONLY; the
// opponent comes from @mentions and every Firebase write stays in the tested
// handlers. Falls back to a keyword classifier when the API errors / returns junk
// so a Claude outage degrades to keyword routing, not a dead bot. Mirrors
// normalizeIntent / classifyIntent / intentCatalog in lib/bot-logic.js. ──
function normalizeNick(s){return String(s==null?'':s).trim().toLowerCase();}
const INTENTS=[
 {intent:'sign_in',description:'The sender wants to join / sign in to the current tournament.',examples:['sign me in','sign-in','add me','I want to join','prihlás ma','zapíš ma']},
 {intent:'report_win',description:'The sender is reporting that they won a match / beat the tagged opponent.',examples:['I beat @player','I defeated @player','I won against @player','porazil som @player','zdolal som @player']},
 {intent:'help',description:'The sender is asking what the bot can do.',examples:['help','what can you do','commands','pomoc']},
 {intent:'start_tournament',description:'The sender wants to start / create a new tournament.',examples:['start tournament','create a tournament','new tournament','začni turnaj','vytvor turnaj']}
];
const INTENT_NAMES=INTENTS.map(i=>i.intent);
function normalizeIntent(raw){const v=String(raw==null?'':raw).trim().toLowerCase().replace(/[-\s]+/g,'_');return INTENT_NAMES.includes(v)?v:'unknown';}
function classifyIntent(text){const t=normalizeNick(text);if(!t)return 'unknown';const has=(...kw)=>kw.some(k=>t.includes(k));if(has('beat','beated','defeat','won','porazil','zdolal','vyhral','vyhrál'))return 'report_win';if(has('sign in','sign-in','signin','add me','join','register','prihlas','prihlás','zapis','zapíš','pridaj'))return 'sign_in';if(has('start tournament','start a tournament','start-tournament','new tournament','create tournament','create a tournament','zacni','začni','vytvor turnaj'))return 'start_tournament';if(has('help','pomoc','command','what can you'))return 'help';return 'unknown';}
function intentCatalog(){return INTENTS.map(i=>'- '+i.intent+': '+i.description+' Examples: '+i.examples.join('; ')+'.').join('\n');}

const cfg=$('Config').first().json;
const p=$('Parse Message').first().json;
const text=String(p.text||'');
let intent=null;
if(cfg.anthropicKey){
  const sys='You are an intent classifier for a WhatsApp tournament bot. Read the user message and reply with ONLY a JSON object {"intent":"<name>"} — no prose, no code fences.\n\nChoose exactly one intent:\n'+intentCatalog()+'\n- unknown: the message matches none of the above.\n\nMessages may be in English, Czech or Slovak. If it does not clearly match a listed intent, use "unknown".';
  try{
    const res=await this.helpers.httpRequest({method:'POST',url:'https://api.anthropic.com/v1/messages',headers:{'x-api-key':cfg.anthropicKey,'anthropic-version':'2023-06-01','content-type':'application/json'},body:{model:cfg.anthropicModel||'claude-haiku-4-5-20251001',max_tokens:64,system:sys,messages:[{role:'user',content:text}]},json:true});
    const raw=(res&&Array.isArray(res.content)&&res.content[0]&&res.content[0].text)?res.content[0].text:'';
    const m=raw.match(/\{[^}]*\}/);
    if(m){intent=normalizeIntent(JSON.parse(m[0]).intent);}
  }catch(e){intent=null;}
}
if(intent===null){intent=classifyIntent(text);}
return [{ json: Object.assign({}, p, { intent }) }];

// ── sign-in: append the sender's nickname (resolved from the Data Table) to the
// tournament's `players` list — the single source of truth the board renders
// (there is no participants node). Case-insensitive dedupe. Mirrors
// addPlayerToList in lib/bot-logic.js. ──
function normalizeNick(s){return String(s==null?'':s).trim().toLowerCase();}
function matchRoster(players,nickname){const t=normalizeNick(nickname);return (players||[]).find(p=>normalizeNick(p)===t)||null;}
function pickLatestTid(pointer,registry){if(pointer&&typeof pointer==='string')return pointer;let best=null,bo=-Infinity;for(const [id,t] of Object.entries(registry||{})){if(!t||id.startsWith('_'))continue;const o=typeof t.order==='number'?t.order:0;if(o>bo){best=id;bo=o;}}return best;}
function addPlayerToList(players,nickname){const list=Array.isArray(players)?players.slice():[];const clean=String(nickname==null?'':nickname).trim();if(!clean)return {ok:false,code:'missing_nickname'};const existing=matchRoster(list,clean);if(existing)return {ok:true,added:false,nickname:existing,players:list};list.push(clean);return {ok:true,added:true,nickname:clean,players:list};}

const cfg=$('Config').first().json;
const p=$('Parse Message').first().json;
const chatId=p.chatId; const M=[p.number]; const who='@'+p.number+' ';
const q=cfg.fbAuth||'';
const row=($input.first()&&$input.first().json)||{};
const nickname=row.nickname?String(row.nickname):'';

async function send(message,mentions){const b={to:chatId,body:message};if(mentions&&mentions.length)b.mentions=mentions;if(cfg.whapiToken){await this.helpers.httpRequest({method:'POST',url:cfg.whapiBase+'/messages/text',headers:{Authorization:'Bearer '+cfg.whapiToken},body:b,json:true});}return [{json:{message:message}}];}

if(!nickname){return await send.call(this,who+'your number is not registered for this tournament.',M);}
const pointer=await this.helpers.httpRequest({url:cfg.fbUrl+'/latest_tournament.json'+q,json:true}).catch(()=>null);
let tid=(pointer&&typeof pointer==='string')?pointer:null;
if(!tid){const reg=await this.helpers.httpRequest({url:cfg.fbUrl+'/tournaments.json'+q,json:true}).catch(()=>({}));tid=pickLatestTid(null,reg||{});}
if(!tid){return await send.call(this,who+'there is no active tournament right now.',M);}
const title=(await this.helpers.httpRequest({url:cfg.fbUrl+'/tournaments/'+tid+'/title.json'+q,json:true}).catch(()=>null))||tid;
const players=await this.helpers.httpRequest({url:cfg.fbUrl+'/tournaments/'+tid+'/players.json'+q,json:true}).catch(()=>[]);
const res=addPlayerToList(players,nickname);
if(res.added){
  await this.helpers.httpRequest({method:'PUT',url:cfg.fbUrl+'/tournaments/'+tid+'/players.json'+q,body:res.players,json:true});
  return await send.call(this,who+'✅ Signed in! '+res.nickname+' is now in '+title+'.',M);
}
return await send.call(this,who+'ℹ️ '+res.nickname+' is already in '+title+'.',M);

// ── help: list the commands, tagging the requester. ──
const cfg = $('Config').first().json;
const p = $('Parse Message').first().json;
const message = '@'+p.number+' Tag me and just tell me what you want — plain words, English/Čeština/Slovenčina:\n• "sign me in" — join the current tournament\n• "I beat @player" — report that you won\n• "help" — show this\n• "start a tournament" — begin one (coming soon)';
const b = { to: p.chatId, body: message, mentions: [p.number] };
if(cfg.whapiToken){ await this.helpers.httpRequest({ method:'POST', url: cfg.whapiBase+'/messages/text', headers:{ Authorization:'Bearer '+cfg.whapiToken }, body: b, json:true }); }
return [{ json:{ sent:'help' } }];

// ── start_tournament: create the next tournament. ONLY the player currently
// ranked #1 in the active tournament may create one (it need not be finished).
// Claude extracts the setup fields from the message; required: style, mapType,
// mapSize, nation (+ gloryTier if glory, + botDifficulty if botCount>0). The new
// tournament is created with an EMPTY players list and set active. Mirrors
// currentLeaders / validateNewTournament / nextTournamentId / buildTournamentEntry
// in lib/bot-logic.js. ──
function normalizeNick(s){return String(s==null?'':s).trim().toLowerCase();}
function pickLatestTid(pointer,registry){if(pointer&&typeof pointer==='string')return pointer;let best=null,bo=-Infinity;for(const [id,t] of Object.entries(registry||{})){if(!t||id.startsWith('_'))continue;const o=typeof t.order==='number'?t.order:0;if(o>bo){best=id;bo=o;}}return best;}
function getResultAt(results,r,c){if(r===c)return null;const key=(a,b)=>a+'-'+b;if(r<c)return (results&&results[key(r,c)])||null;const v=(results&&results[key(c,r)])||null;if(!v)return null;return v==='1:0'?'0:1':'1:0';}
function calcStandings(players,results){const N=(players||[]).length;const stats=[];for(let i=0;i<N;i++){let wins=0,losses=0,played=0,remaining=0;for(let j=0;j<N;j++){if(i===j)continue;const r=getResultAt(results,i,j);if(r==='1:0'){wins++;played++;}else if(r==='0:1'){losses++;played++;}else remaining++;}stats.push({idx:i,wins:wins,losses:losses,played:played,remaining:remaining,pts:wins});}return stats;}
function rankStandings(stats,results){const h2h=(a,b)=>{const r=getResultAt(results,a,b);if(r==='1:0')return -1;if(r==='0:1')return 1;return 0;};const beatAll=(idx,group)=>group.every(o=>o.idx===idx?true:getResultAt(results,idx,o.idx)==='1:0');const grouped={};stats.forEach(s=>{(grouped[s.pts]=grouped[s.pts]||[]).push(s);});const result=[];Object.keys(grouped).map(Number).sort((a,b)=>b-a).forEach(pts=>{const group=grouped[pts];if(group.length===1){group[0].isTied=false;result.push(group[0]);}else if(group.length===2){const h=h2h(group[0].idx,group[1].idx);if(h<0){group[0].isTied=false;group[1].isTied=false;result.push(group[0],group[1]);}else if(h>0){group[0].isTied=false;group[1].isTied=false;result.push(group[1],group[0]);}else{group[0].isTied=true;group[1].isTied=true;result.push(group[0],group[1]);}}else{const winners=group.filter(pp=>beatAll(pp.idx,group));if(winners.length===1){winners[0].isTied=false;const rest=group.filter(pp=>pp.idx!==winners[0].idx);rest.forEach(pp=>pp.isTied=true);result.push(winners[0],...rest.sort((a,b)=>b.wins-a.wins||a.losses-b.losses));}else{group.forEach(pp=>pp.isTied=true);result.push(...group.sort((a,b)=>b.wins-a.wins||a.losses-b.losses));}}});return result;}
function currentLeaders(players,results){const list=players||[];const ranked=rankStandings(calcStandings(list,results),results);const top=ranked[0];if(!top||top.pts<=0)return [];if(!top.isTied)return [list[top.idx]];const leaders=[];for(const s of ranked){if(s.pts===top.pts&&s.isTied)leaders.push(list[s.idx]);else break;}return leaders;}
function validateNewTournament(fields){const s=fields||{};const missing=[];const style=String(s.style==null?'':s.style).toLowerCase();if(style!=='might'&&style!=='glory')missing.push('style (might or glory)');if(!s.mapType)missing.push('map type');if(!s.mapSize)missing.push('map size');if(!s.nation)missing.push('nation');if(style==='glory'&&!s.gloryTier)missing.push('glory tier');const bots=(s.botCount==null||s.botCount==='')?0:Number(s.botCount);if(bots>0&&!s.botDifficulty)missing.push('bot difficulty');return {ok:missing.length===0,missing:missing};}
function nextTournamentId(registry){let maxOrder=0;for(const [id,t] of Object.entries(registry||{})){if(!t||id.startsWith('_'))continue;const o=typeof t.order==='number'?t.order:0;if(o>maxOrder)maxOrder=o;}let order=maxOrder+1;let id='t'+order;while(registry&&Object.prototype.hasOwnProperty.call(registry,id)){order++;id='t'+order;}return {id:id,order:order};}
function buildTournamentEntry(fields,order){const s=fields||{};const style=String(s.style==null?'':s.style).toLowerCase();const setup={mapType:s.mapType,mapSize:s.mapSize,nation:s.nation,style:style};if(style==='glory')setup.gloryTier=s.gloryTier;const bots=(s.botCount==null||s.botCount==='')?0:Number(s.botCount);if(bots>0){setup.botCount=bots;setup.botDifficulty=s.botDifficulty;}return {order:order,title:'Tournament '+order,legacy:false,setup:setup,players:[]};}

const cfg=$('Config').first().json;
const p=$('Parse Message').first().json;
const chatId=p.chatId; const M=[p.number]; const who='@'+p.number+' ';
const q=cfg.fbAuth||'';
const row=($input.first()&&$input.first().json)||{};
const creator=row.nickname?String(row.nickname):'';

async function send(message,mentions){const b={to:chatId,body:message};if(mentions&&mentions.length)b.mentions=mentions;if(cfg.whapiToken){await this.helpers.httpRequest({method:'POST',url:cfg.whapiBase+'/messages/text',headers:{Authorization:'Bearer '+cfg.whapiToken},body:b,json:true});}return [{json:{message:message}}];}

if(!creator){return await send.call(this,who+"your number is not registered, so you can't create a tournament.",M);}

// 1) Authorize: creator must lead the current tournament (if one exists).
const pointer=await this.helpers.httpRequest({url:cfg.fbUrl+'/latest_tournament.json'+q,json:true}).catch(()=>null);
const registry=await this.helpers.httpRequest({url:cfg.fbUrl+'/tournaments.json'+q,json:true}).catch(()=>({}));
const curTid=pickLatestTid((pointer&&typeof pointer==='string')?pointer:null,registry||{});
if(curTid){
  const cur=(registry&&registry[curTid])||{};
  const curTitle=cur.title||curTid;
  const leaders=currentLeaders(cur.players||[],cur.results||{});
  if(leaders.length===0){return await send.call(this,who+'no one leads '+curTitle+' yet — play some matches there first.',M);}
  if(!leaders.some(n=>normalizeNick(n)===normalizeNick(creator))){return await send.call(this,who+'only the current leader ('+leaders.join(', ')+') of '+curTitle+' can start a new tournament.',M);}
}

// 2) Extract the setup fields from the message (Claude).
let fields=null;
if(cfg.anthropicKey){
  const sys='Extract Polytopia tournament setup from the user message. Reply with ONLY a JSON object with keys: style ("might"|"glory"|null), gloryTier (string|null), mapType (string|null), mapSize (string|null), nation (string|null), botCount (integer|null), botDifficulty (string|null). Use null for anything not stated. Messages may be English, Czech or Slovak.';
  try{
    const res=await this.helpers.httpRequest({method:'POST',url:'https://api.anthropic.com/v1/messages',headers:{'x-api-key':cfg.anthropicKey,'anthropic-version':'2023-06-01','content-type':'application/json'},body:{model:cfg.anthropicModel||'claude-haiku-4-5-20251001',max_tokens:300,system:sys,messages:[{role:'user',content:String(p.text||'')}]},json:true});
    const raw=(res&&Array.isArray(res.content)&&res.content[0]&&res.content[0].text)?res.content[0].text:'';
    const m=raw.match(/\{[\s\S]*\}/);
    if(m){fields=JSON.parse(m[0]);}
  }catch(e){fields=null;}
}
if(!fields){return await send.call(this,who+'I couldn\'t read the tournament details. Include style, map type, map size and nation (e.g. "glory 15k, Drylands, Normal, Ai-Mo, 14 Crazy bots").',M);}

// 3) Validate required fields.
const v=validateNewTournament(fields);
if(!v.ok){return await send.call(this,who+'❌ can\'t create — missing: '+v.missing.join(', ')+'. Send them and try again.',M);}

// 4) Create + activate.
const next=nextTournamentId(registry||{});
const entry=buildTournamentEntry(fields,next.order);
await this.helpers.httpRequest({method:'PUT',url:cfg.fbUrl+'/tournaments/'+next.id+'.json'+q,body:entry,json:true});
await this.helpers.httpRequest({method:'PUT',url:cfg.fbUrl+'/latest_tournament.json'+q,body:JSON.stringify(next.id),headers:{'Content-Type':'application/json'}});
const su=entry.setup;
const desc='Style: '+(su.style==='glory'?('Glory '+(su.gloryTier||'')):'Might')+' · Map: '+su.mapType+' · Size: '+su.mapSize+' · Nation: '+su.nation+(su.botCount?(' · Bots: '+su.botCount+' '+(su.botDifficulty||'')):'');
const url=String(cfg.hubUrl||'').replace(/\/+$/,'')+'/#t='+next.id;
return await send.call(this,who+'✅ Created '+entry.title+' ('+next.id+') and set it active.\n'+desc+'\n🔗 '+url+'\nSign in with "@bot sign me in".',M);

// ── report_win ("I beat @player"): record the result. Winner = sender, loser =
// tagged opponent; both nicknames resolved via the Data Table (Get Opponent, then
// Get Sender). Writes the positional results/<a>-<b> (drives ranking) AND
// scores/<a>-<b> (explicit winner + notified:false → announce workflow) exactly
// like the web app's saveScore. buildWinRecord is the tested logic in
// lib/bot-logic.js — keep in sync. ──
function normalizeNick(s){return String(s==null?'':s).trim().toLowerCase();}
function matchRoster(players,nickname){const t=normalizeNick(nickname);return (players||[]).find(p=>normalizeNick(p)===t)||null;}
function pickLatestTid(pointer,registry){if(pointer&&typeof pointer==='string')return pointer;let best=null,bo=-Infinity;for(const [id,t] of Object.entries(registry||{})){if(!t||id.startsWith('_'))continue;const o=typeof t.order==='number'?t.order:0;if(o>bo){best=id;bo=o;}}return best;}
function buildWinRecord({players,winner,loser,now}){const list=players||[];const wName=matchRoster(list,winner);const lName=matchRoster(list,loser);if(!wName)return {ok:false,code:'winner_not_on_roster'};if(!lName)return {ok:false,code:'loser_not_on_roster'};if(normalizeNick(wName)===normalizeNick(lName))return {ok:false,code:'same_player'};const wi=list.findIndex(p=>normalizeNick(p)===normalizeNick(wName));const li=list.findIndex(p=>normalizeNick(p)===normalizeNick(lName));const a=Math.min(wi,li),b=Math.max(wi,li);const matchId=a+'-'+b;const resultVal=wi===a?'1:0':'0:1';const score={result:resultVal,winner_nickname:wName,loser_nickname:lName,row_nickname:list[a],col_nickname:list[b],match_id:matchId,notified:false,created_at:(now||Date.now)()};return {ok:true,matchId:matchId,resultVal:resultVal,score:score,winner:wName,loser:lName};}

const cfg=$('Config').first().json;
const p=$('Parse Message').first().json;
const chatId=p.chatId;
const q=cfg.fbAuth||'';
const target=(p.targetPlayers&&p.targetPlayers[0])||'';
const oppRow=($('Get Opponent (Data Table)').first()&&$('Get Opponent (Data Table)').first().json)||{};
const senderRow=($input.first()&&$input.first().json)||{};
const oppNick=oppRow.nickname?String(oppRow.nickname):'';
const winnerNick=senderRow.nickname?String(senderRow.nickname):'';

async function send(message,mentions){const b={to:chatId,body:message};if(mentions&&mentions.length)b.mentions=mentions;if(cfg.whapiToken){await this.helpers.httpRequest({method:'POST',url:cfg.whapiBase+'/messages/text',headers:{Authorization:'Bearer '+cfg.whapiToken},body:b,json:true});}return [{json:{message:message}}];}

if(!target){return await send.call(this,'@'+p.number+' tag the player you beat, e.g. "@bot I beat @player".',[p.number]);}
if(!winnerNick){return await send.call(this,'@'+p.number+' your number is not registered for this tournament.',[p.number]);}
if(!oppNick){return await send.call(this,'@'+p.number+" I don't recognize @"+target+' as a registered player.',[p.number,target]);}

const pointer=await this.helpers.httpRequest({url:cfg.fbUrl+'/latest_tournament.json'+q,json:true}).catch(()=>null);
let tid=(pointer&&typeof pointer==='string')?pointer:null;
if(!tid){const reg=await this.helpers.httpRequest({url:cfg.fbUrl+'/tournaments.json'+q,json:true}).catch(()=>({}));tid=pickLatestTid(null,reg||{});}
if(!tid){return await send.call(this,'@'+p.number+' there is no active tournament right now.',[p.number]);}
const players=await this.helpers.httpRequest({url:cfg.fbUrl+'/tournaments/'+tid+'/players.json'+q,json:true}).catch(()=>[]);
const rec=buildWinRecord({players:players,winner:winnerNick,loser:oppNick});
if(!rec.ok){
  if(rec.code==='winner_not_on_roster'){return await send.call(this,'@'+p.number+' "'+winnerNick+'" is not on the player list for '+tid+'.',[p.number]);}
  if(rec.code==='loser_not_on_roster'){return await send.call(this,'@'+p.number+' @'+target+' ("'+oppNick+'") is not on the player list for '+tid+'.',[p.number,target]);}
  if(rec.code==='same_player'){return await send.call(this,'@'+p.number+" you can't report a win against yourself.",[p.number]);}
  return await send.call(this,'@'+p.number+" couldn't record that result.",[p.number]);
}
// Firebase RTDB needs a JSON *value* for the leaf. n8n/axios sends a string body
// verbatim, so a bare "1:0" arrives unquoted and RTDB 400s — JSON.stringify it.
await this.helpers.httpRequest({method:'PUT',url:cfg.fbUrl+'/tournaments/'+tid+'/results/'+rec.matchId+'.json'+q,body:JSON.stringify(rec.resultVal),headers:{'Content-Type':'application/json'}});
await this.helpers.httpRequest({method:'PUT',url:cfg.fbUrl+'/tournaments/'+tid+'/scores/'+rec.matchId+'.json'+q,body:rec.score,json:true});
return await send.call(this,'@'+p.number+' ✅ Recorded: '+rec.winner+' beat @'+target+' ('+rec.loser+') in '+tid+'.',[p.number,target]);

// ── unknown intent → funny AI chat. The bot only reaches here when @mentioned
// with something that isn't a command, so it never spams the group. It pulls the
// last ~30 group messages from Whapi for context and fires back a short, playful
// roast in the group's language. buildTranscript is tested in lib/bot-logic.js. ──
function buildTranscript(messages,opts){const o=opts||{};const limit=o.limit||30;const botName=o.botName||'PolyBot';const list=(Array.isArray(messages)?messages:[]).filter(m=>m&&m.text&&typeof m.text.body==='string'&&m.text.body.trim()).sort((a,b)=>(a.timestamp||0)-(b.timestamp||0)).slice(-limit);return list.map(m=>(m.from_me?botName:(m.from_name||'someone'))+': '+m.text.body.trim()).join('\n');}

const cfg=$('Config').first().json;
const p=$('Parse Message').first().json;
const chatId=p.chatId; const M=[p.number]; const who='@'+p.number+' ';

async function send(message,mentions){const b={to:chatId,body:message};if(mentions&&mentions.length)b.mentions=mentions;if(cfg.whapiToken){await this.helpers.httpRequest({method:'POST',url:cfg.whapiBase+'/messages/text',headers:{Authorization:'Bearer '+cfg.whapiToken},body:b,json:true});}return [{json:{message:message}}];}

// Pull recent group context from Whapi (best-effort; no context is fine too).
let transcript='';
if(cfg.whapiToken){
  try{
    const res=await this.helpers.httpRequest({method:'GET',url:cfg.whapiBase+'/messages/list/'+encodeURIComponent(chatId)+'?count=30&sort=desc',headers:{Authorization:'Bearer '+cfg.whapiToken},json:true});
    const arr=(res&&Array.isArray(res.messages))?res.messages:(Array.isArray(res)?res:[]);
    transcript=buildTranscript(arr,{limit:30,botName:'PolyBot'});
  }catch(e){transcript='';}
}

